// ✗ Using index as key — input values follow the wrong rows after prepend
import { useState } from 'react';

function BadList() {
  const [items, setItems] = useState([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);

  function prepend() {
    setItems(prev => [{ id: Date.now(), name: 'New' }, ...prev]);
  }

  return (
    <>
      <button onClick={prepend}>Prepend</button>
      <ul>
        {items.map((item, i) => (
          // key=i means 'New' gets the input DOM node that Alice was using
          <li key={i}>
            {item.name}: <input defaultValue="" />
          </li>
        ))}
      </ul>
    </>
  );
}

// ✓ Stable key — input state preserved correctly
{items.map(item => (
  <li key={item.id}>
    {item.name}: <input defaultValue="" />
  </li>
))}

// ✗ key on inner element — React warns and uses position for the outer <li>
{items.map(item => (
  <li>               {/* <-- this needs the key */}
    <span key={item.id}>{item.name}</span>  {/* key here does nothing useful */}
  </li>
))}

// ✓ key on the outermost element from the callback
{items.map(item => (
  <li key={item.id}>
    <span>{item.name}</span>
  </li>
))}

// ✓ key on component — React tracks the component instance
{items.map(item => (
  <ItemCard key={item.id} item={item} />
))}

import { Fragment } from 'react';

function Glossary({ terms }) {
  return (
    <dl>
      {terms.map(term => (
        // <> shorthand cannot accept a key prop — use Fragment explicitly
        <Fragment key={term.id}>
          <dt>{term.word}</dt>
          <dd>{term.definition}</dd>
        </Fragment>
      ))}
    </dl>
  );
}

// When userId changes, the Form component fully remounts (fresh state)
// No useEffect cleanup or manual reset needed
function ProfilePage({ userId }) {
  return <ProfileForm key={userId} userId={userId} />;
}

// The same technique for tabs that should reset when switching
function Tabs({ activeTab }) {
  return <TabContent key={activeTab} tab={activeTab} />;
}

import { useState, useId } from 'react';

// Option 1: assign at data-creation time
function TodoApp() {
  const [todos, setTodos] = useState([]);

  function addTodo(text) {
    setTodos(prev => [
      ...prev,
      { id: crypto.randomUUID(), text },  // stable, generated once
    ]);
  }

  return (
    <ul>
      {todos.map(t => <li key={t.id}>{t.text}</li>)}
    </ul>
  );
}

// Option 2: useId for static lists (SSR-safe)
function LabeledInputs({ fields }) {
  const prefix = useId();
  return fields.map((f, i) => (
    <label key={`${prefix}-${i}`}>
      {f.label}: <input />
    </label>
  ));
}

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { TodoList } from './TodoList';

test('existing input value preserved when new item prepended', async () => {
  const { rerender } = render(
    <TodoList items={[{ id: 1, label: 'First' }]} />
  );

  // Type into the first item's input
  const input = screen.getByRole('textbox');
  await userEvent.type(input, 'my note');

  // Re-render with a new item prepended
  rerender(
    <TodoList items={[
      { id: 2, label: 'Second' },
      { id: 1, label: 'First' },
    ]} />
  );

  // 'First' item should still have its typed value
  const inputs = screen.getAllByRole('textbox');
  expect(inputs[1]).toHaveValue('my note'); // id=1 is now at index 1
  expect(inputs[0]).toHaveValue('');         // id=2 starts empty
});

import { AnimatePresence, motion } from 'framer-motion';

function AnimatedList({ items }) {
  return (
    <AnimatePresence>
      {items.map(item => (
        // stable key lets AnimatePresence detect removals and play exit animation
        <motion.li
          key={item.id}
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: 20 }}
        >
          {item.name}
        </motion.li>
      ))}
    </AnimatePresence>
  );
}

import { Suspense, lazy } from 'react';

const HeavyCard = lazy(() => import('./HeavyCard'));

function CardList({ cards }) {
  return (
    <ul>
      {cards.map(card => (
        <li key={card.id}>
          {/* Stable key ensures only THIS card's fallback shows */}
          <Suspense fallback={<Skeleton />}>
            <HeavyCard card={card} />
          </Suspense>
        </li>
      ))}
    </ul>
  );
}

import { useState } from 'react';

function DraggableList({ initialItems }) {
  const [items, setItems] = useState(initialItems);
  const [dragging, setDragging] = useState(null);

  function handleDragStart(id) {
    setDragging(id);
  }

  function handleDrop(targetId) {
    if (!dragging || dragging === targetId) return;
    setItems(prev => {
      const from = prev.findIndex(i => i.id === dragging);
      const to   = prev.findIndex(i => i.id === targetId);
      const next = [...prev];
      [next[from], next[to]] = [next[to], next[from]];
      return next;
    });
    setDragging(null);
  }

  return (
    <ul>
      {items.map(item => (
        // key={item.id} ensures React moves the real DOM node instead of recreating it
        <li
          key={item.id}
          draggable
          onDragStart={() => handleDragStart(item.id)}
          onDragOver={e => e.preventDefault()}
          onDrop={() => handleDrop(item.id)}
          style={{ opacity: dragging === item.id ? 0.4 : 1 }}
        >
          {item.label}
        </li>
      ))}
    </ul>
  );
}
